/* eslint-disable no-nested-ternary, no-unused-vars, complexity, no-negated-condition, no-empty-pattern */
import {
  Mjml,
  MjmlAll,
  MjmlAttributes,
  MjmlBody,
  MjmlColumn,
  MjmlHead,
  MjmlImage,
  MjmlPreview,
  MjmlSection,
  MjmlText,
  MjmlWrapper,
} from "@faire/mjml-react";

import { defaultTheme } from "@/components/emails/themes/mjml-default";
import type { EmailThemeTokens } from "@/components/emails/themes/mjml-default";

export type ImageRoundedVariant = "default" | "slanted-left" | "slanted-right";

export interface ImageRoundedProps {
  theme?: EmailThemeTokens;
  src?: string;
  alt?: string;
  size?: number;
  variant?: ImageRoundedVariant;
}

const ImageRoundedSection = ({
  alt,
  size,
  src,
  theme,
  variant,
}: {
  alt: string;
  size: number;
  src: string;
  theme: EmailThemeTokens;
  variant: ImageRoundedVariant;
}) => (
  <MjmlSection
    backgroundColor={theme.colorBackground}
    padding={`${theme.spacingXl ?? "48px"} 0`}
  >
    <MjmlColumn>
      <MjmlImage
        align="center"
        alt={alt}
        borderRadius="50%"
        src={src}
        width={size}
        height={size}
      />
    </MjmlColumn>
  </MjmlSection>
);

export const ThreeColumnsMasonryImageGrid = ({
  theme = defaultTheme,
  src = "https://api.dicebear.com/9.x/lorelei/png?seed=grid-avatar-1&size=200",
  alt = "avatar",
  size = 200,
  variant = "default",
}: ImageRoundedProps) => (
  <Mjml>
    <MjmlHead>
      <MjmlPreview>rounded image</MjmlPreview>
      <MjmlAttributes>
        <MjmlAll color={theme.colorTextMuted} fontFamily={theme.fontFamily} />
        <MjmlText
          fontSize={theme.fontSizeBase}
          lineHeight={theme.lineHeightBase}
        />
      </MjmlAttributes>
    </MjmlHead>
    <MjmlBody
      backgroundColor={theme.colorBackground}
      width={theme.containerWidth}
    >
      <MjmlWrapper padding="0">
        <ImageRoundedSection
          alt={alt}
          size={size}
          src={src}
          theme={theme}
          variant={variant}
        />
      </MjmlWrapper>
    </MjmlBody>
  </Mjml>
);

ThreeColumnsMasonryImageGrid.PreviewProps = {
  alt: "profile photo",
  size: 200,
  src: "https://api.dicebear.com/9.x/lorelei/png?seed=grid-avatar-2&size=200",
  theme: defaultTheme,
  variant: "default",
} satisfies ImageRoundedProps;
